import{_ as e,o as s,c as i,a2 as t}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"ItemLoreOrigin 符文转换","description":"","frontmatter":{},"headers":[],"relativePath":"gtgem/conversion.md","filePath":"gtgem/conversion.md","lastUpdated":null}'),n={name:"gtgem/conversion.md"};function p(l,a,o,d,h,c){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="itemloreorigin-符文转换" tabindex="-1">ItemLoreOrigin 符文转换 <a class="header-anchor" href="#itemloreorigin-符文转换" aria-label="Permalink to &quot;ItemLoreOrigin 符文转换&quot;">​</a></h1><p>转换功能用于把旧 ItemLoreOrigin 符文模板一次性转换成 GTGem 符文。转换完成后 GTGem 不依赖 ItemLoreOrigin，也不会在服务器运行期间监听或读取它。</p><h2 id="转换范围" tabindex="-1">转换范围 <a class="header-anchor" href="#转换范围" aria-label="Permalink to &quot;转换范围&quot;">​</a></h2><p>GTGem 只读取：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>plugins/ItemLoreOrigin/config.yml</span></span></code></pre></div><p>并转换其中的：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Inlay</span></span></code></pre></div><p>不会扫描玩家背包、箱子、实体掉落或在线玩家装备，也不会自动修改现有物品。</p><h2 id="执行转换" tabindex="-1">执行转换 <a class="header-anchor" href="#执行转换" aria-label="Permalink to &quot;执行转换&quot;">​</a></h2><p>确认旧配置仍在原位置，然后执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtgem convert itemloreorigin</span></span></code></pre></div><p>转换结果保存到：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>plugins/GTGem/converted/ItemLoreOrigin.yml</span></span></code></pre></div><p>GTGem 保存后会立即回读并校验每一个物品的 NBT。回读失败时命令会直接报告失败，不会把未通过校验的数量算作成功。</p><h2 id="查看结果" tabindex="-1">查看结果 <a class="header-anchor" href="#查看结果" aria-label="Permalink to &quot;查看结果&quot;">​</a></h2><p>列出已转换符文：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtgem convert list</span></span></code></pre></div><p>把指定转换结果发给自己：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtgem convert give 符文ID</span></span></code></pre></div><p>发给其他在线玩家：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtgem convert give 符文ID 玩家名</span></span></code></pre></div><h2 id="转换后的结构" tabindex="-1">转换后的结构 <a class="header-anchor" href="#转换后的结构" aria-label="Permalink to &quot;转换后的结构&quot;">​</a></h2><p>旧符文会转换为 <code>compact</code> 显示模式：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">display</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;compact&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  style</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;rune&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  template</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;§孔§位&amp;7符文: {slots}&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  empty</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&amp;8□&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  mark</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&amp;c◆&quot;</span></span></code></pre></div><p><code>mark</code> 会优先读取旧符文自己的标记。能够识别为数值的旧 Lore 属性会写入 <code>gtgem.attributes</code>，其余无法安全判断的文本会记录到转换文件的 <code>unparsed-lore</code>，方便人工确认，不会静默丢弃。</p><h2 id="转换后检查" tabindex="-1">转换后检查 <a class="header-anchor" href="#转换后检查" aria-label="Permalink to &quot;转换后检查&quot;">​</a></h2><ol><li>执行 <code>/gtgem convert list</code>，确认数量。</li><li>使用 <code>/gtgem convert give</code> 领取一个结果。</li><li>手持符文执行 <code>/gtgem debug item</code>。</li><li>准备一件带 <code>符文槽</code> 的 GTGem 装备。</li><li>使用 <code>/gtgem open rune</code> 完成一次镶嵌和拆卸。</li><li>确认属性、符号、空槽位和拆卸还原都符合旧系统效果。</li></ol>`,27)])])}const k=e(n,[["render",p]]);export{g as __pageData,k as default};
